using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,a[MAXN],sum=0,l,r,c,b;
signed main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
	n=read();
	FOR(i,1,n)
	{
		a[i]=read();
		sum+=a[i];
	}
	l=read(),r=read();
	if(sum>r*n||sum<l*n)
	{
		NoAns
		exit(false);
	}
	FOR(i,1,n)
	{
		if(a[i]>r)c+=a[i]-r;
		if(a[i]<l)b+=l-a[i];
	}
	write(max(b,c));
    return false;
}
